<script setup></script>
<style>
/* Base styles for the logo container */
.animated-logo {
	cursor: pointer;
	transition: transform 0.3s ease;
}

/* Default state for all paths */
.animated-logo path {
	transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
	transform-origin: center center;
	fill: var(--cyan);
}

/* .animated-logo path:nth-child(1),
.animated-logo path:nth-child(2),
.animated-logo path:nth-child(3),
.animated-logo path:nth-child(4),
.animated-logo path:nth-child(5),
.animated-logo path:nth-child(6),
.animated-logo path:nth-child(7),
.animated-logo path:nth-child(8) {
	display: none;
	@media (min-width: theme('screens.md')) {
		display: inline-block;
	}
} */

/* Hover effect on the SVG container */
.animated-logo:hover path:nth-child(1),
.animated-logo:hover path:nth-child(2),
.animated-logo:hover path:nth-child(3) {
	transform: translateX(-8px);
}

/* Middle section paths move upward */
.animated-logo:hover path:nth-child(4),
.animated-logo:hover path:nth-child(5),
.animated-logo:hover path:nth-child(6),
.animated-logo:hover path:nth-child(7),
.animated-logo:hover path:nth-child(8),
.animated-logo:hover path:nth-child(9),
.animated-logo:hover path:nth-child(10) {
	transform: translateY(-6px);
}

/* End section paths move right */
.animated-logo:hover path:nth-child(11),
.animated-logo:hover path:nth-child(12),
.animated-logo:hover path:nth-child(13),
.animated-logo:hover path:nth-child(14),
.animated-logo:hover path:nth-child(15) {
	transform: translateX(8px);
}

/* Add staggered delay for more fluid animation */
.animated-logo path:nth-child(1) {
	transition-delay: 0.02s;
}
.animated-logo path:nth-child(2) {
	transition-delay: 0.04s;
}
.animated-logo path:nth-child(3) {
	transition-delay: 0.06s;
}
.animated-logo path:nth-child(4) {
	transition-delay: 0.08s;
}
.animated-logo path:nth-child(5) {
	transition-delay: 0.1s;
}
.animated-logo path:nth-child(6) {
	transition-delay: 0.12s;
}
.animated-logo path:nth-child(7) {
	transition-delay: 0.14s;
}
.animated-logo path:nth-child(8) {
	transition-delay: 0.16s;
}
.animated-logo path:nth-child(9) {
	transition-delay: 0.18s;
}
.animated-logo path:nth-child(10) {
	transition-delay: 0.2s;
}
.animated-logo path:nth-child(11) {
	transition-delay: 0.22s;
}
.animated-logo path:nth-child(12) {
	transition-delay: 0.24s;
}
.animated-logo path:nth-child(13) {
	transition-delay: 0.26s;
}
.animated-logo path:nth-child(14) {
	transition-delay: 0.28s;
}
.animated-logo path:nth-child(15) {
	transition-delay: 0.3s;
}

/* Optional: Add a subtle scale effect to the entire logo on hover */
.animated-logo:hover {
	transform: scale(1.02);
}
</style>
